				var segment, index;

				if (currentEl.attr("class") === pie.cssPrefix + "arc")
				{
					segment = currentEl.select("path");
				} else
				{
					index = currentEl.attr("data-index");
					segment = d3.select("#" + pie.cssPrefix + "segment" + index);
				}

